import {
  Component, ChangeDetectionStrategy, input, output, inject, computed,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { NGX_DATE_TIME_ADAPTER } from '../../../tokens/date-time-adapter.token';
import { NGX_LABELS } from '../../../tokens/labels.token';
import { NgxDateTimeAdapter } from '../../../adapters/date-time-adapter';
import { RangePreset } from '../../../models/preset.model';

/**
 * Preset quick-select panel displayed on the left of range picker panels.
 * Emits the preset key when a preset is selected.
 */
@Component({
  selector: 'ngx-presets-panel',
  standalone: true,
  imports: [CommonModule],
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <div class="ngx-presets" role="listbox" [attr.aria-label]="'Quick select'">
      <button
        *ngFor="let preset of presets()"
        class="ngx-presets__btn"
        [class.ngx-presets__btn--active]="activeKey() === preset.key"
        [attr.aria-selected]="activeKey() === preset.key"
        role="option"
        type="button"
        (click)="onSelect(preset)"
      >
        {{ preset.label }}
      </button>
    </div>
  `,
})
export class NgxPresetsPanelComponent<D> {
  private readonly adapter = inject<NgxDateTimeAdapter<D>>(NGX_DATE_TIME_ADAPTER as never);
  protected readonly labels = inject(NGX_LABELS);

  readonly presets = input.required<RangePreset<D>[]>();
  readonly activeKey = input<string | null>(null);

  readonly presetSelected = output<RangePreset<D>>();

  protected onSelect(preset: RangePreset<D>): void {
    this.presetSelected.emit(preset);
  }
}

