import {
  Component, ChangeDetectionStrategy, input, output, model, inject,
  computed, signal, effect, OnDestroy, ElementRef, ViewChild, forwardRef,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { ControlValueAccessor, NG_VALUE_ACCESSOR, ReactiveFormsModule } from '@angular/forms';
import { OverlayModule, Overlay, OverlayRef, PositionStrategy } from '@angular/cdk/overlay';
import { ComponentPortal } from '@angular/cdk/portal';
import { A11yModule } from '@angular/cdk/a11y';
import { NgxDateTimeAdapter } from '../../adapters/date-time-adapter';
import { NGX_DATE_TIME_ADAPTER } from '../../tokens/date-time-adapter.token';
import { NGX_DATE_TIME_FORMATS, NgxDateTimeFormats } from '../../tokens/date-time-formats.token';
import { NGX_LABELS, NgxLabels } from '../../tokens/labels.token';
import { DateTimeRange, createEmptyDateTimeRange } from '../../models/date-range.model';
import { TimeValue, createTimeValue, timeValueFromDate, applyTimeToDate } from '../../models/time-value.model';
import { RangePreset } from '../../models/preset.model';
import { NgxCalendarComponent } from '../shared/calendar/ngx-calendar.component';
import { NgxTimeSelectorComponent } from '../shared/time-selector/ngx-time-selector.component';
import { NgxPresetsPanelComponent } from '../shared/presets-panel/ngx-presets-panel.component';
import { formatDuration } from '../../utilities/date-utils';

/**
 * DateTime Range Picker — full-featured component with:
 * - Dual calendar view
 * - Start/End time selectors
 * - Preset quick-select
 * - Angular CDK Overlay (popover on desktop, bottom-sheet on mobile)
 * - ControlValueAccessor + model() signal for both Reactive Forms and Signal Forms
 *
 * Design decision: The panel is inlined (not in a portal) to keep template
 * change detection simple and avoid the complexity of cross-component DI in portals.
 * On mobile the panel overlays fullscreen via the `--mobile` class.
 */
@Component({
  selector: 'ngx-date-time-range-picker',
  standalone: true,
  imports: [
    CommonModule,
    NgxCalendarComponent,
    NgxTimeSelectorComponent,
    NgxPresetsPanelComponent,
  ],
  changeDetection: ChangeDetectionStrategy.OnPush,
  providers: [
    {
      provide: NG_VALUE_ACCESSOR,
      useExisting: forwardRef(() => NgxDateTimeRangePickerComponent),
      multi: true,
    },
  ],
  template: `
    <div class="ngx-picker-field"
         [class.ngx-picker-field--open]="isOpen()"
         [class.ngx-picker-field--disabled]="disabled()"
         [class.ngx-picker-field--invalid]="invalid()"
         [attr.aria-haspopup]="'dialog'"
         [attr.aria-expanded]="isOpen()"
         [attr.aria-label]="labels.selectDateTime"
         (click)="togglePanel()"
         (keydown.enter)="openPanel()"
         (keydown.space)="openPanel(); $event.preventDefault()"
         tabindex="0"
         role="button">
      <!-- Calendar Icon -->
      <span class="ngx-picker-field__icon" aria-hidden="true">
        <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
          <rect x="3" y="4" width="18" height="18" rx="2"/>
          <line x1="16" y1="2" x2="16" y2="6"/>
          <line x1="8" y1="2" x2="8" y2="6"/>
          <line x1="3" y1="10" x2="21" y2="10"/>
        </svg>
      </span>

      <!-- Value display -->
      <span class="ngx-picker-field__value">
        <ng-container *ngIf="displayValue(); else placeholder">
          {{ displayValue() }}
        </ng-container>
        <ng-template #placeholder>
          <span class="ngx-picker-field__placeholder">{{ placeholderText() }}</span>
        </ng-template>
      </span>

      <!-- Clear button -->
      <button
        *ngIf="displayValue() && !disabled()"
        class="ngx-picker-field__clear"
        type="button"
        [attr.aria-label]="labels.clearValue"
        (click)="clearValue($event)"
        tabindex="-1"
      >
        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
          <line x1="18" y1="6" x2="6" y2="18"/>
          <line x1="6" y1="6" x2="18" y2="18"/>
        </svg>
      </button>
    </div>

    <!-- Inline Panel (shown when isOpen) -->
    <div
      *ngIf="isOpen()"
      class="ngx-panel"
      [class.ngx-panel--mobile]="isMobile()"
      role="dialog"
      [attr.aria-label]="labels.selectPeriod"
      [attr.aria-modal]="true"
      (keydown.escape)="cancelPanel()"
    >
      <!-- Panel Header -->
      <div class="ngx-panel__header">
        <div>
          <h2 class="ngx-panel__title">{{ labels.selectPeriod }}</h2>
          <p class="ngx-panel__preview" *ngIf="rangePreviewText()">{{ rangePreviewText() }}</p>
        </div>
        <button
          class="ngx-panel__close"
          type="button"
          [attr.aria-label]="labels.closePanel"
          (click)="cancelPanel()"
        >
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
            <line x1="18" y1="6" x2="6" y2="18"/>
            <line x1="6" y1="6" x2="18" y2="18"/>
          </svg>
        </button>
      </div>

      <!-- Panel Body -->
      <div class="ngx-panel__body">
        <!-- Presets -->
        <ngx-presets-panel
          [presets]="effectivePresets()"
          [activeKey]="activePresetKey()"
          (presetSelected)="onPresetSelected($event)"
        />

        <!-- Dual Calendar -->
        <div class="ngx-panel__calendars">
          <ngx-calendar
            [viewYear]="leftYear()"
            [viewMonth]="leftMonth()"
            [rangeStart]="pendingStart()"
            [rangeEnd]="pendingEnd()"
            [hoverDate]="hoverDate()"
            [minDate]="minDate()"
            [maxDate]="maxDate()"
            [showPrevNav]="true"
            [showNextNav]="false"
            (daySelected)="onDaySelected($event)"
            (onDayHover)="hoverDate.set($event)"
            (prevMonthClicked)="navigateLeft(-1)"
            (nextMonthClicked)="navigateLeft(1)"
          />
          <ngx-calendar
            [viewYear]="rightYear()"
            [viewMonth]="rightMonth()"
            [rangeStart]="pendingStart()"
            [rangeEnd]="pendingEnd()"
            [hoverDate]="hoverDate()"
            [minDate]="minDate()"
            [maxDate]="maxDate()"
            [showPrevNav]="false"
            [showNextNav]="true"
            (daySelected)="onDaySelected($event)"
            (onDayHover)="hoverDate.set($event)"
            (prevMonthClicked)="navigateRight(-1)"
            (nextMonthClicked)="navigateRight(1)"
          />
        </div>

        <!-- Time Panel -->
        <div class="ngx-panel__time-panel">
          <div class="ngx-panel__time-block">
            <h3 class="ngx-panel__time-label">{{ labels.startTime }}</h3>
            <ngx-time-selector
              [value]="pendingStartTime()"
              [showSeconds]="showSeconds()"
              [label]="labels.startTime"
              (timeChanged)="onStartTimeChanged($event)"
            />
          </div>
          <div class="ngx-panel__time-block">
            <h3 class="ngx-panel__time-label">{{ labels.endTime }}</h3>
            <ngx-time-selector
              [value]="pendingEndTime()"
              [showSeconds]="showSeconds()"
              [label]="labels.endTime"
              (timeChanged)="onEndTimeChanged($event)"
            />
          </div>
          <div class="ngx-panel__duration" *ngIf="durationText()">
            {{ labels.duration }}: {{ durationText() }}
          </div>
        </div>
      </div>

      <!-- Panel Footer -->
      <div class="ngx-panel__footer">
        <span class="ngx-panel__footer-preview">{{ rangePreviewText() }}</span>
        <div class="ngx-panel__actions">
          <button class="ngx-btn ngx-btn--ghost" type="button" (click)="cancelPanel()">
            {{ labels.cancel }}
          </button>
          <button
            class="ngx-btn ngx-btn--primary"
            type="button"
            [disabled]="!canApply()"
            (click)="applyPanel()"
          >
            {{ labels.apply }}
          </button>
        </div>
      </div>
    </div>
  `,
})
export class NgxDateTimeRangePickerComponent<D> implements ControlValueAccessor, OnDestroy {
  private readonly adapter = inject<NgxDateTimeAdapter<D>>(NGX_DATE_TIME_ADAPTER as never);
  protected readonly labels = inject(NGX_LABELS);
  private readonly formats = inject(NGX_DATE_TIME_FORMATS);

  // ── Inputs ──────────────────────────────────────────────────────────────────
  /** Two-way bindable value — works directly with Signal Forms model() */
  readonly value = model<DateTimeRange<D> | null>(null);

  readonly placeholder = input<string>('');
  readonly disabled = input<boolean>(false);
  readonly invalid = input<boolean>(false);
  readonly showSeconds = input<boolean>(true);
  readonly minDate = input<D | null>(null);
  readonly maxDate = input<D | null>(null);
  /** Custom presets — if omitted, default presets are shown. */
  readonly customPresets = input<RangePreset<D>[] | null>(null);

  // ── Internal state ───────────────────────────────────────────────────────────
  protected readonly isOpen = signal(false);
  protected readonly isMobile = signal(false);

  /** Pending selection — committed to `value` only on Apply */
  protected readonly pendingStart = signal<D | null>(null);
  protected readonly pendingEnd = signal<D | null>(null);
  protected readonly pendingStartTime = signal<TimeValue>(createTimeValue(0, 0, 0));
  protected readonly pendingEndTime = signal<TimeValue>(createTimeValue(23, 59, 59));
  protected readonly hoverDate = signal<D | null>(null);
  protected readonly activePresetKey = signal<string | null>('custom');

  /** Which month is shown in the left calendar */
  protected readonly leftMonth = signal(new Date().getMonth());
  protected readonly leftYear = signal(new Date().getFullYear());

  // ── Computed: right calendar is always one month after left ──────────────────
  protected readonly rightMonth = computed(() => (this.leftMonth() + 1) % 12);
  protected readonly rightYear = computed(() =>
    this.leftMonth() === 11 ? this.leftYear() + 1 : this.leftYear(),
  );

  // ── Computed: display ────────────────────────────────────────────────────────
  protected readonly displayValue = computed(() => {
    const v = this.value();
    if (!v?.start || !v?.end) return null;
    const fmt = this.formats.display.dateTimeInput;
    return `${this.adapter.format(v.start, fmt)} – ${this.adapter.format(v.end, fmt)}`;
  });

  protected readonly placeholderText = computed(
    () => this.placeholder() || `${this.formats.display.dateTimeInput} – ${this.formats.display.dateTimeInput}`,
  );

  protected readonly rangePreviewText = computed(() => {
    const s = this.pendingStart();
    const e = this.pendingEnd();
    if (!s) return null;
    const fmt = this.formats.display.dateTimeInput;
    const startStr = this.adapter.format(
      this.adapter.setTime(s, this.pendingStartTime().hours, this.pendingStartTime().minutes, this.pendingStartTime().seconds),
      fmt,
    );
    if (!e) return startStr;
    const endStr = this.adapter.format(
      this.adapter.setTime(e, this.pendingEndTime().hours, this.pendingEndTime().minutes, this.pendingEndTime().seconds),
      fmt,
    );
    return `${startStr} – ${endStr}`;
  });

  protected readonly durationText = computed(() => {
    const s = this.pendingStart();
    const e = this.pendingEnd();
    if (!s || !e) return null;
    const start = this.adapter.setTime(s, this.pendingStartTime().hours, this.pendingStartTime().minutes, this.pendingStartTime().seconds);
    const end = this.adapter.setTime(e, this.pendingEndTime().hours, this.pendingEndTime().minutes, this.pendingEndTime().seconds);
    if (this.adapter.compare(start, end) > 0) return null;
    const ms = this.adapter.diffInMs(start, end);
    return formatDuration(ms);
  });

  protected readonly canApply = computed(() =>
    this.pendingStart() !== null && this.pendingEnd() !== null,
  );

  // ── Default presets ──────────────────────────────────────────────────────────
  protected readonly effectivePresets = computed<RangePreset<D>[]>(() => {
    if (this.customPresets()) return this.customPresets()!;
    const a = this.adapter;
    return [
      {
        key: 'today', label: this.labels.today,
        getRangeFn: () => ({ start: a.today(), end: a.today() }),
      },
      {
        key: 'last24h', label: this.labels.last24h,
        getRangeFn: () => ({ start: a.addHours(a.now(), -24), end: a.now() }),
      },
      {
        key: 'thisWeek', label: this.labels.thisWeek,
        getRangeFn: () => {
          const now = a.today();
          const dow = a.getDayOfWeek(now);
          const diff = (dow - a.getFirstDayOfWeek() + 7) % 7;
          return { start: a.addDays(now, -diff), end: now };
        },
      },
      {
        key: 'last7Days', label: this.labels.last7Days,
        getRangeFn: () => ({ start: a.addDays(a.today(), -6), end: a.today() }),
      },
      {
        key: 'thisMonth', label: this.labels.thisMonth,
        getRangeFn: () => {
          const now = a.today();
          return {
            start: a.createDate(a.getYear(now), a.getMonth(now), 1),
            end: now,
          };
        },
      },
      { key: 'custom', label: this.labels.custom, getRangeFn: () => ({ start: a.today(), end: a.today() }) },
    ];
  });

  // ── ControlValueAccessor ─────────────────────────────────────────────────────
  private onChange: (v: DateTimeRange<D> | null) => void = () => {};
  private onTouched: () => void = () => {};

  writeValue(val: DateTimeRange<D> | null): void {
    this.value.set(val);
  }

  registerOnChange(fn: (v: DateTimeRange<D> | null) => void): void { this.onChange = fn; }
  registerOnTouched(fn: () => void): void { this.onTouched = fn; }
  setDisabledState(isDisabled: boolean): void { /* handled by disabled input */ }

  // ── Panel lifecycle ──────────────────────────────────────────────────────────
  protected togglePanel(): void {
    if (this.disabled()) return;
    this.isOpen() ? this.cancelPanel() : this.openPanel();
  }

  protected openPanel(): void {
    if (this.disabled() || this.isOpen()) return;
    this.isMobile.set(window.innerWidth < 768);
    // Seed pending state from current value
    const v = this.value();
    if (v?.start) {
      this.pendingStart.set(this.adapter.startOfDay(v.start));
      this.pendingStartTime.set(createTimeValue(
        this.adapter.getHours(v.start),
        this.adapter.getMinutes(v.start),
        this.adapter.getSeconds(v.start),
      ));
    } else {
      this.pendingStart.set(null);
      this.pendingStartTime.set(createTimeValue(0, 0, 0));
    }
    if (v?.end) {
      this.pendingEnd.set(this.adapter.startOfDay(v.end));
      this.pendingEndTime.set(createTimeValue(
        this.adapter.getHours(v.end),
        this.adapter.getMinutes(v.end),
        this.adapter.getSeconds(v.end),
      ));
    } else {
      this.pendingEnd.set(null);
      this.pendingEndTime.set(createTimeValue(23, 59, 59));
    }

    // Set left calendar to start month (or current month)
    const ref = this.pendingStart() ?? this.adapter.today();
    this.leftMonth.set(this.adapter.getMonth(ref));
    this.leftYear.set(this.adapter.getYear(ref));

    this.isOpen.set(true);
  }

  protected cancelPanel(): void {
    this.isOpen.set(false);
    this.onTouched();
  }

  protected applyPanel(): void {
    const s = this.pendingStart();
    const e = this.pendingEnd();
    if (!s || !e) return;

    const st = this.pendingStartTime();
    const et = this.pendingEndTime();

    const start = this.adapter.setTime(s, st.hours, st.minutes, st.seconds);
    const end = this.adapter.setTime(e, et.hours, et.minutes, et.seconds);

    const range: DateTimeRange<D> = { start, end };
    this.value.set(range);
    this.onChange(range);
    this.onTouched();
    this.activePresetKey.set('custom');
    this.isOpen.set(false);
  }

  protected clearValue(event: MouseEvent): void {
    event.stopPropagation();
    this.value.set(null);
    this.onChange(null);
    this.onTouched();
  }

  // ── Day selection logic ──────────────────────────────────────────────────────
  protected onDaySelected(date: D): void {
    const s = this.pendingStart();
    const e = this.pendingEnd();
    this.activePresetKey.set('custom');

    if (!s || (s && e)) {
      // Start a new selection
      this.pendingStart.set(date);
      this.pendingEnd.set(null);
      this.hoverDate.set(null);
    } else {
      // Complete the range
      if (this.adapter.compareDateOnly(date, s) < 0) {
        this.pendingEnd.set(s);
        this.pendingStart.set(date);
      } else {
        this.pendingEnd.set(date);
      }
      this.hoverDate.set(null);
    }
  }

  // ── Preset selection ─────────────────────────────────────────────────────────
  protected onPresetSelected(preset: RangePreset<D>): void {
    if (preset.key === 'custom') {
      this.activePresetKey.set('custom');
      return;
    }
    const { start, end } = preset.getRangeFn();
    this.pendingStart.set(this.adapter.startOfDay(start));
    this.pendingEnd.set(this.adapter.startOfDay(end));
    this.pendingStartTime.set(timeValueFromDate(start as unknown as Date) as unknown as TimeValue);
    this.pendingEndTime.set(timeValueFromDate(end as unknown as Date) as unknown as TimeValue);

    const month = this.adapter.getMonth(start);
    const year = this.adapter.getYear(start);
    this.leftMonth.set(month);
    this.leftYear.set(year);
    this.activePresetKey.set(preset.key);
  }

  // ── Time changes ─────────────────────────────────────────────────────────────
  protected onStartTimeChanged(time: TimeValue): void {
    this.pendingStartTime.set(time);
    this.activePresetKey.set('custom');
  }

  protected onEndTimeChanged(time: TimeValue): void {
    this.pendingEndTime.set(time);
    this.activePresetKey.set('custom');
  }

  // ── Calendar navigation ──────────────────────────────────────────────────────
  protected navigateLeft(delta: number): void {
    let m = this.leftMonth() + delta;
    let y = this.leftYear();
    if (m < 0) { m = 11; y--; }
    else if (m > 11) { m = 0; y++; }
    this.leftMonth.set(m);
    this.leftYear.set(y);
  }

  protected navigateRight(delta: number): void {
    this.navigateLeft(delta);
  }

  ngOnDestroy(): void {}
}

