import {
  Component, ChangeDetectionStrategy, input, output, computed,
  inject, signal, effect, OnInit,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { NgxDateTimeAdapter } from '../../../adapters/date-time-adapter';
import { NGX_DATE_TIME_ADAPTER } from '../../../tokens/date-time-adapter.token';
import { NGX_LABELS } from '../../../tokens/labels.token';
import { buildCalendarGrid } from '../../../utilities/date-utils';

export interface CalendarCell<D> {
  date: D;
  isCurrentMonth: boolean;
  dayNumber: number;
}

/**
 * Shared calendar grid component.
 * Renders a single month with navigation arrows and emits day selections.
 * Supports range highlighting when both rangeStart and rangeEnd are provided.
 *
 * Design decision: This is a "dumb" component — it renders whatever state
 * is passed in via inputs and delegates all decisions to the parent picker.
 */
@Component({
  selector: 'ngx-calendar',
  standalone: true,
  imports: [CommonModule],
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <div class="ngx-calendar" role="grid" [attr.aria-label]="monthYearLabel()">
      <!-- Header: Month Navigation -->
      <div class="ngx-calendar__header">
        <button
          *ngIf="showPrevNav()"
          class="ngx-calendar__nav-btn"
          type="button"
          (click)="onPrevMonth()"
          [attr.aria-label]="labels.previousMonth"
        >
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5">
            <polyline points="15 18 9 12 15 6"/>
          </svg>
        </button>
        <span *ngIf="!showPrevNav()" class="ngx-calendar__nav-spacer"></span>

        <span class="ngx-calendar__month-title">{{ monthYearLabel() }}</span>

        <button
          *ngIf="showNextNav()"
          class="ngx-calendar__nav-btn"
          type="button"
          (click)="onNextMonth()"
          [attr.aria-label]="labels.nextMonth"
        >
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5">
            <polyline points="9 18 15 12 9 6"/>
          </svg>
        </button>
        <span *ngIf="!showNextNav()" class="ngx-calendar__nav-spacer"></span>
      </div>

      <!-- Weekday Names -->
      <div class="ngx-calendar__grid" role="row">
        <div
          *ngFor="let wd of weekdayNames()"
          class="ngx-calendar__weekday"
          role="columnheader"
          [attr.aria-label]="wd"
        >{{ wd }}</div>
      </div>

      <!-- Day Cells -->
      <div class="ngx-calendar__grid">
        <button
          *ngFor="let cell of cells()"
          class="ngx-calendar__day"
          [class.ngx-calendar__day--other-month]="!cell.isCurrentMonth"
          [class.ngx-calendar__day--today]="isToday(cell.date)"
          [class.ngx-calendar__day--selected]="isSelected(cell.date)"
          [class.ngx-calendar__day--range-start]="isRangeStart(cell.date)"
          [class.ngx-calendar__day--range-end]="isRangeEnd(cell.date)"
          [class.ngx-calendar__day--in-range]="isInRange(cell.date)"
          [class.ngx-calendar__day--disabled]="isDisabled(cell.date)"
          [attr.aria-pressed]="isSelected(cell.date)"
          [attr.aria-disabled]="isDisabled(cell.date)"
          [attr.aria-label]="dayAriaLabel(cell.date)"
          [disabled]="isDisabled(cell.date)"
          role="gridcell"
          type="button"
          (click)="onDayClick(cell.date)"
          (keydown.enter)="onDayClick(cell.date)"
          (keydown.space)="onDayClick(cell.date)"
          (mouseenter)="onDayHover.emit(cell.date)"
        >
          <span aria-hidden="true">{{ cell.dayNumber }}</span>
        </button>
      </div>
    </div>
  `,
})
export class NgxCalendarComponent<D> implements OnInit {
  private readonly adapter = inject<NgxDateTimeAdapter<D>>(NGX_DATE_TIME_ADAPTER as never);
  protected readonly labels = inject(NGX_LABELS);

  // ── Inputs ──────────────────────────────────────────────────────────────────
  /** Displayed month (0-based) */
  readonly viewMonth = input.required<number>();
  /** Displayed year */
  readonly viewYear = input.required<number>();
  /** Currently selected single date (for date/datetime pickers) */
  readonly selectedDate = input<D | null>(null);
  /** Range start */
  readonly rangeStart = input<D | null>(null);
  /** Range end */
  readonly rangeEnd = input<D | null>(null);
  /** Hover candidate (for range hover preview) */
  readonly hoverDate = input<D | null>(null);
  /** Min selectable date */
  readonly minDate = input<D | null>(null);
  /** Max selectable date */
  readonly maxDate = input<D | null>(null);
  /** Disabled individual dates */
  readonly disabledDates = input<D[]>([]);
  /** Show/hide navigation arrows */
  readonly showPrevNav = input<boolean>(true);
  readonly showNextNav = input<boolean>(true);

  // ── Outputs ─────────────────────────────────────────────────────────────────
  readonly daySelected = output<D>();
  readonly onDayHover = output<D>();
  readonly prevMonthClicked = output<void>();
  readonly nextMonthClicked = output<void>();

  // ── Computed ─────────────────────────────────────────────────────────────────
  protected readonly weekdayNames = computed(() =>
    this.adapter.getWeekdayNames('narrow', this.adapter.getFirstDayOfWeek()),
  );

  protected readonly monthNames = computed(() => this.adapter.getMonthNames('long'));

  protected readonly monthYearLabel = computed(() => {
    const name = this.monthNames()[this.viewMonth()];
    return `${name} ${this.viewYear()}`;
  });

  protected readonly cells = computed<CalendarCell<D>[]>(() =>
    buildCalendarGrid(
      this.viewYear(),
      this.viewMonth(),
      this.adapter.getFirstDayOfWeek(),
      this.adapter,
    ).map(cell => ({
      date: cell.date,
      isCurrentMonth: cell.isCurrentMonth,
      dayNumber: this.adapter.getDate(cell.date),
    })),
  );

  ngOnInit(): void {}

  // ── Helper predicates ────────────────────────────────────────────────────────

  protected isToday(date: D): boolean {
    return this.adapter.isSameDay(date, this.adapter.today());
  }

  protected isSelected(date: D): boolean {
    return this.selectedDate() !== null && this.adapter.isSameDay(date, this.selectedDate()!);
  }

  protected isRangeStart(date: D): boolean {
    return this.rangeStart() !== null && this.adapter.isSameDay(date, this.rangeStart()!);
  }

  protected isRangeEnd(date: D): boolean {
    return this.rangeEnd() !== null && this.adapter.isSameDay(date, this.rangeEnd()!);
  }

  protected isInRange(date: D): boolean {
    const start = this.rangeStart();
    const end = this.rangeEnd() ?? this.hoverDate();
    if (!start || !end) return false;
    if (this.adapter.compareDateOnly(start, end) > 0) {
      return this.adapter.isInRangeDateOnly(date, end, start);
    }
    return this.adapter.isInRangeDateOnly(date, start, end);
  }

  protected isDisabled(date: D): boolean {
    const min = this.minDate();
    const max = this.maxDate();
    if (min && this.adapter.compareDateOnly(date, min) < 0) return true;
    if (max && this.adapter.compareDateOnly(date, max) > 0) return true;
    return this.disabledDates().some(d => this.adapter.isSameDay(d, date));
  }

  protected dayAriaLabel(date: D): string {
    return this.adapter.format(date, 'dd. MM. yyyy');
  }

  protected onDayClick(date: D): void {
    if (!this.isDisabled(date)) {
      this.daySelected.emit(date);
    }
  }

  protected onPrevMonth(): void { this.prevMonthClicked.emit(); }
  protected onNextMonth(): void { this.nextMonthClicked.emit(); }
}

